Here is a comprehensive suite of unit tests for the `zip_dicts` function using `pytest`. 

The tests are categorized into **Happy Path** (normal usage), **Edge Cases** (boundary conditions and unusual but valid inputs), and **Error Cases** (invalid inputs).

```python
import pytest

# The function to be tested
def zip_dicts(*dicts) -> dict:
    keys = set().union(*dicts)
    return {k: [d.get(k) for d in dicts] for k in keys}


# ==========================================
# HAPPY PATH TESTS
# ==========================================

def test_zip_dicts_same_keys():
    """Test with dictionaries that have the exact same keys."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'a': 3, 'b': 4}
    expected = {'a': [1, 3], 'b': [2, 4]}
    assert zip_dicts(d1, d2) == expected

def test_zip_dicts_overlapping_keys():
    """Test with dictionaries that share some keys but not all."""
    d1 = {'a': 1, 'b': 2}
    d2 = {'b': 3, 'c': 4}
    expected = {'a': [1, None], 'b': [2, 3], 'c': [None, 4]}
    assert zip_dicts(d1, d2) == expected

def test_zip_dicts_disjoint_keys():
    """Test with dictionaries that have completely different keys."""
    d1 = {'a': 1}
    d2 = {'b': 2}
    expected = {'a': [1, None], 'b': [None, 2]}
    assert zip_dicts(d1, d2) == expected

def test_zip_dicts_multiple_dicts():
    """Test with more than two dictionaries."""
    d1 = {'a': 1}
    d2 = {'a': 2, 'b': 3}
    d3 = {'c': 4}
    expected = {
        'a': [1, 2, None],
        'b': [None, 3, None],
        'c': [None, None, 4]
    }
    assert zip_dicts(d1, d2, d3) == expected


# ==========================================
# EDGE CASE TESTS
# ==========================================

def test_zip_dicts_no_args():
    """Test calling the function with no arguments."""
    assert zip_dicts() == {}

def test_zip_dicts_one_arg():
    """Test calling the function with a single dictionary."""
    d1 = {'a': 1, 'b': 2}
    expected = {'a': [1], 'b': [2]}
    assert zip_dicts(d1) == expected

def test_zip_dicts_empty_dicts():
    """Test calling the function with empty dictionaries."""
    assert zip_dicts({}, {}) == {}

def test_zip_dicts_mixed_key_types():
    """Test with dictionaries containing different hashable key types."""
    d1 = {1: 'one', (1, 2): 'tuple'}
    d2 = {1: 'uno', 'string': 'str'}
    expected = {
        1: ['one', 'uno'],
        (1, 2): ['tuple', None],
        'string': [None, 'str']
    }
    assert zip_dicts(d1, d2) == expected

def test_zip_dicts_with_none_values():
    """Test dictionaries where the actual value is None."""
    d1 = {'a': None}
    d2 = {}
    # The first None is the actual value, the second is the default from .get()
    expected = {'a': [None, None]} 
    assert zip_dicts(d1, d2) == expected


# ==========================================
# ERROR CASE TESTS
# ==========================================

def test_zip_dicts_invalid_type_iterable():
    """
    Test passing an iterable that is not a dict (e.g., a list).
    set().union() will succeed, but d.get() will raise an AttributeError.
    """
    d1 = {'a': 1}
    invalid_dict = ['a', 'b']
    with pytest.raises(AttributeError):
        zip_dicts(d1, invalid_dict)

def test_zip_dicts_invalid_type_non_iterable():
    """
    Test passing a non-iterable (e.g., an integer).
    set().union() will immediately raise a TypeError.
    """
    d1 = {'a': 1}
    invalid_dict = 5
    with pytest.raises(TypeError):
        zip_dicts(d1, invalid_dict)
```

### How to run these tests:
1. Save the code in a file named `test_zip_dicts.py`.
2. Ensure you have `pytest` installed (`pip install pytest`).
3. Run the tests from your terminal using the command:
   ```bash
   pytest test_zip_dicts.py -v
   ```
